mapper.select:
SELECT b.type, b.id, b.actual, b.inv_status AS invStatus, IFNULL(i.opened_amount, 0) AS openedAmount FROM (
SELECT 'buy' AS type, id, actual, invoice AS inv_status FROM buy WHERE id IN #{id} UNION ALL
SELECT 'bre' AS type, id, actual, invoice AS inv_status FROM bre WHERE id IN #{id} UNION ALL
SELECT 'sell' AS type, id, actual, invoice AS inv_status FROM sell WHERE id IN #{id} UNION ALL
SELECT 'sre' AS type, id, actual, invoice AS inv_status FROM sre WHERE id IN #{id}
) b LEFT JOIN ( SELECT `type`, `class` AS bill_id, SUM(money) AS opened_amount FROM invoice GROUP BY `type`, `class` ) i ON i.`type` = b.type AND i.bill_id = b.id

SELECT inv.id AS id, inv.`type` AS `type`, f.`name` AS frame, COALESCE(cu.`name`, su.`name`) AS businessUnit, bill.`time` AS `time`, bill.`number` AS `number`, bill.`actual` AS `total`, inv.`time` AS invTime, inv.`number` AS invNumber, /* 状态字段 DTO 里有，虽然导出不展示，顺带算出无妨 */ CASE WHEN bill.inv_status = 3 THEN '无需开具' WHEN IFNULL(inv_sum.opened_amount, 0) = 0 THEN '未开票' WHEN IFNULL(inv_sum.opened_amount, 0) < bill.`actual` THEN '部分开票' ELSE '已开票' END AS `invoice`, inv.`title` AS `title`, inv.`money` AS invMoney, inv.`file` AS `file`, inv.`data` AS `data` FROM invoice inv LEFT JOIN ( SELECT 'buy' AS `type`, b.`id`, b.`frame`, b.`supplier` AS unit_id, b.`time`, b.`number`, b.`actual`, b.`invoice` AS inv_status FROM buy b UNION ALL SELECT 'bre' AS `type`, br.`id`, br.`frame`, br.`supplier` AS unit_id, br.`time`, br.`number`, br.`actual`, br.`invoice` AS inv_status FROM bre br UNION ALL SELECT 'sell' AS `type`, s.`id`, s.`frame`, s.`customer` AS unit_id, s.`time`, s.`number`, s.`actual`, s.`invoice` AS inv_status FROM sell s UNION ALL SELECT 'sre' AS `type`, sr.`id`, sr.`frame`, sr.`customer` AS unit_id, sr.`time`, sr.`number`, sr.`actual`, sr.`invoice` AS inv_status FROM sre sr ) bill ON bill.`type` = inv.`type` AND bill.`id` = inv.`class` LEFT JOIN ( SELECT `type`, `class`, SUM(`money`) AS opened_amount FROM invoice GROUP BY `type`, `class` ) inv_sum ON inv_sum.`type` = inv.`type` AND inv_sum.`class` = inv.`class` LEFT JOIN frame f ON f.`id` = bill.`frame` LEFT JOIN supplier su ON (inv.`type` IN ('buy','bre') AND su.`id` = bill.`unit_id`) LEFT JOIN customer cu ON (inv.`type` IN ('sell','sre') AND cu.`id` = bill.`unit_id`) WHERE 1 = 1 AND inv.`id` IN
#{id}
ORDER BY inv.`time` DESC, inv.`number` DESC
